// ─── Intent Node ───────────────────────────────────────────────────────────
// Classifies incoming Slack messages and extracts structured intent.
// Only passes reporting-related messages downstream.
// Non-reporting messages are flagged and halted.

const event = $input.first().json;

// Extract message text from various Slack event structures
const text = (
  event?.event?.text ||
  event?.text ||
  event?.message?.text ||
  ''
).trim().toLowerCase();

const rawText = (
  event?.event?.text ||
  event?.text ||
  event?.message?.text ||
  ''
).trim();

const channelId = event?.event?.channel || event?.channel || '';
const userId    = event?.event?.user    || event?.user    || '';
const ts        = event?.event?.ts      || event?.ts      || '';

// ── 1. Detect bot messages (avoid loops) ──────────────────────────────────
const isBotMessage = event?.event?.bot_id || event?.bot_id;
if (isBotMessage) {
  return [{ json: { pass: false, reason: 'bot_message', channelId, ts } }];
}

// ── 2. Intent classification keywords ─────────────────────────────────────
const reportKeywords    = ['report', 'summary', 'stats', 'statistics', 'status', 'overview', 'breakdown'];
const projectKeywords   = ['project', 'task', 'tasks', 'work package', 'sprint', 'milestone'];
const userKeywords      = ['user', 'person', 'individual', 'who', 'performance', 'team member', 'assigned'];
const dateKeywords      = ['today', 'yesterday', 'week', 'month', 'days', 'last', 'past', 'since', 'from', 'to', 'between'];

const hasReport  = reportKeywords.some(k  => text.includes(k));
const hasProject = projectKeywords.some(k => text.includes(k));
const hasUser    = userKeywords.some(k    => text.includes(k));

const isReportingRequest = hasReport || (hasProject && !hasUser) || (hasProject && hasUser);

if (!isReportingRequest) {
  return [{ json: {
    pass: false,
    reason: 'not_reporting_intent',
    channelId,
    userId,
    ts,
    originalText: rawText
  }}];
}

// ── 3. Classify report type ────────────────────────────────────────────────
let reportType = 'project';
if (hasProject && hasUser)  reportType = 'both';
else if (hasUser && !hasProject) reportType = 'individual';
else if (hasProject)             reportType = 'project';

// ── 4. Extract date range ──────────────────────────────────────────────────
let daysBack = 7; // default
let dateRangeLabel = 'Last 7 days';

const todayMatch     = text.match(/\btoday\b/);
const yesterdayMatch = text.match(/\byesterday\b/);
const lastNDaysMatch = text.match(/(last|past)\s+(\d+)\s+day/);
const lastWeekMatch  = text.match(/last\s+week/);
const lastMonthMatch = text.match(/last\s+month/);
const nDaysMatch     = text.match(/(\d+)\s+day/);

if (todayMatch) {
  daysBack = 1; dateRangeLabel = 'Today';
} else if (yesterdayMatch) {
  daysBack = 2; dateRangeLabel = 'Yesterday';
} else if (lastNDaysMatch) {
  daysBack = parseInt(lastNDaysMatch[2]); dateRangeLabel = `Last ${daysBack} days`;
} else if (nDaysMatch) {
  daysBack = parseInt(nDaysMatch[1]); dateRangeLabel = `Last ${daysBack} days`;
} else if (lastWeekMatch) {
  daysBack = 7; dateRangeLabel = 'Last 7 days';
} else if (lastMonthMatch) {
  daysBack = 30; dateRangeLabel = 'Last 30 days';
}

// ── 5. Extract project name hint ──────────────────────────────────────────
// Look for quoted project names: report for "ProjectX" or 'ProjectX'
const quotedName = rawText.match(/["']([^"']+)["']/);
const projectHint = quotedName ? quotedName[1] : null;

// ── 6. Build structured output ─────────────────────────────────────────────
return [{ json: {
  pass: true,
  reportType,
  daysBack,
  dateRangeLabel,
  projectHint,
  channelId,
  userId,
  ts,
  originalText: rawText,
  prompt: `${rawText}\n\n[Intent: ${reportType} report | Date range: ${dateRangeLabel} | Days back: ${daysBack}${projectHint ? ` | Project hint: ${projectHint}` : ''}]`
}}];

const BASE_URL = 'REPLACE_WITH_YOUR_OPENPROJECT_URL';
const API_KEY  = 'REPLACE_WITH_YOUR_OPENPROJECT_API_KEY';

try {
  const res = await fetch(`${BASE_URL}/api/v3/projects?pageSize=100`, {
    headers: {
      'Authorization': 'Basic ' + btoa(`apikey:${API_KEY}`),
      'Content-Type': 'application/json'
    }
  });

  if (!res.ok) return JSON.stringify({ error: `HTTP ${res.status} ${res.statusText}` });

  const data = await res.json();
  const projects = (data._embedded?.elements || []).map(p => ({
    id: p.id,
    name: p.name,
    identifier: p.identifier,
    status: p.active ? 'active' : 'inactive'
  }));

  return JSON.stringify({ count: projects.length, projects });
} catch (err) {
  return JSON.stringify({ error: err.message });
}

const BASE_URL  = 'REPLACE_WITH_YOUR_OPENPROJECT_URL';
const API_KEY   = 'REPLACE_WITH_YOUR_OPENPROJECT_API_KEY';

const projectId = $fromAI('project_id', 'Numeric project ID from get_projects', '');
const daysBack  = parseInt($fromAI('days_back', 'Number of days to look back. 0 = all time.', '7'), 10);

if (!projectId) return JSON.stringify({ error: 'project_id is required' });

try {
  // Build filters
  const filters = [];
  if (daysBack > 0) {
    filters.push({ updatedAt: { operator: '><t-', values: [String(daysBack)] } });
  }

  const params = new URLSearchParams({
    pageSize: '500',
    filters: JSON.stringify(filters)
  });

  const res = await fetch(
    `${BASE_URL}/api/v3/projects/${projectId}/work_packages?${params.toString()}`,
    {
      headers: {
        'Authorization': 'Basic ' + btoa(`apikey:${API_KEY}`),
        'Content-Type': 'application/json'
      }
    }
  );

  if (!res.ok) return JSON.stringify({ error: `HTTP ${res.status} ${res.statusText}` });

  const data = await res.json();
  const packages = (data._embedded?.elements || []).map(wp => ({
    id: wp.id,
    subject: wp.subject,
    status: wp._links?.status?.title || 'Unknown',
    assignee: wp._links?.assignee?.title || 'Unassigned',
    createdAt: wp.createdAt,
    updatedAt: wp.updatedAt,
    dueDate: wp.dueDate || null
  }));

  return JSON.stringify({ total: packages.length, workPackages: packages });
} catch (err) {
  return JSON.stringify({ error: err.message });
}

const raw         = $fromAI('work_packages_json', 'Full JSON string returned by get_work_packages');
const projectName = $fromAI('project_name', 'Project name', 'Unknown Project');
const dateRange   = $fromAI('date_range', 'Human-readable date range', 'Last 7 days');
const reportType  = $fromAI('report_type', 'project | individual | both', 'both');

// ── Parse ──────────────────────────────────────────────────────────────────
let packages = [];
try {
  const parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
  packages = parsed.workPackages || parsed._embedded?.elements || [];
  if (!Array.isArray(packages)) packages = [];
} catch(e) {
  return `Error parsing work packages: ${e.message}`;
}

// ── Normalize status ───────────────────────────────────────────────────────
const normalize = s => {
  if (!s) return 'Other';
  const v = s.toLowerCase();
  if (/done|closed|finish|complet/.test(v))     return 'Done';
  if (/progress|active|start|open|new/.test(v)) return 'In Progress';
  if (/test|review|qa|staging/.test(v))         return 'Testing';
  return 'Other';
};

// ── Aggregate ──────────────────────────────────────────────────────────────
const total = packages.length;
let done = 0, inProg = 0, testing = 0;
const userMap = {};

for (const wp of packages) {
  const st  = normalize(wp.status);
  const usr = wp.assignee || 'Unassigned';

  if (st === 'Done')        done++;
  else if (st === 'In Progress') inProg++;
  else if (st === 'Testing')     testing++;

  if (!userMap[usr]) userMap[usr] = { total:0, done:0, inProg:0, testing:0 };
  userMap[usr].total++;
  if (st === 'Done')        userMap[usr].done++;
  else if (st === 'In Progress') userMap[usr].inProg++;
  else if (st === 'Testing')     userMap[usr].testing++;
}

const pct = (n, t) => t === 0 ? '0.00%' : ((n/t)*100).toFixed(2)+'%';

// ── Build tables ───────────────────────────────────────────────────────────
const outputs = [];

if (reportType === 'project' || reportType === 'both') {
  const rows = [
    ['Project Name',      projectName],
    ['Date Range',        dateRange],
    ['Total Tasks',       total],
    ['Completed Tasks',   done],
    ['In Progress Tasks', inProg],
    ['Testing Tasks',     testing],
    ['Completion %',      pct(done,  total)],
    ['In Progress %',     pct(inProg, total)],
    ['Testing %',         pct(testing, total)]
  ];
  const tbl = [
    '| Metric                | Value         |',
    '|----------------------|---------------|',
    ...rows.map(([m,v]) => `| ${m.padEnd(20)} | ${String(v).padEnd(13)} |`)
  ].join('\n');
  outputs.push('*Project Report*\n```\n' + tbl + '\n```');
}

if (reportType === 'individual' || reportType === 'both') {
  const header = '| User                 | Total | Done  | In Prog | Testing | Done % |';
  const sep    = '|----------------------|-------|-------|---------|---------|--------|';
  const rows   = Object.entries(userMap).map(([u, d]) =>
    `| ${u.substring(0,20).padEnd(20)} | ${String(d.total).padEnd(5)} | ${String(d.done).padEnd(5)} | ${String(d.inProg).padEnd(7)} | ${String(d.testing).padEnd(7)} | ${pct(d.done,d.total).padEnd(6)} |`
  );
  const tbl = [header, sep, ...rows].join('\n');
  outputs.push('*Individual Performance Report*\n```\n' + tbl + '\n```');
}

return outputs.join('\n\n') || '_(No data)_';
